import type { Metadata, Viewport } from "next";
import Link from "next/link";
import { Inter, JetBrains_Mono } from "next/font/google";
import "./globals.css";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-sans",
  display: "swap",
});

const jetbrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-mono",
  display: "swap",
});

export const metadata: Metadata = {
  metadataBase: new URL("https://example.com"),
  title: {
    default: "Sales Marketing Network",
    template: "%s · Sales Marketing Network",
  },
  description:
    "Collaborative sales marketing workspace for pipeline management, team performance analytics, and real-time execution.",
  applicationName: "Sales Marketing Network",
  keywords: [
    "sales",
    "marketing",
    "CRM",
    "analytics",
    "pipeline",
    "dashboard",
    "team collaboration",
  ],
  openGraph: {
    title: "Sales Marketing Network",
    description:
      "Collaborative sales marketing workspace for pipeline management, team performance analytics, and real-time execution.",
    type: "website",
    siteName: "Sales Marketing Network",
  },
  twitter: {
    card: "summary_large_image",
    title: "Sales Marketing Network",
    description:
      "Real-time sales collaboration, performance dashboards, and analytics for distributed teams.",
  },
  robots: {
    index: true,
    follow: true,
  },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: light)", color: "#ffffff" },
    { media: "(prefers-color-scheme: dark)", color: "#0b1020" },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const currentYear = new Date().getFullYear();

  return (
    <html lang="en" suppressHydrationWarning>
      <body className={`${inter.variable} ${jetbrainsMono.variable}`}>
        <a className="skip-link" href="#main-content">
          Skip to main content
        </a>

        <div className="app-shell">
          <header className="app-header" role="banner">
            <div className="container header-inner">
              <div className="brand-block" aria-label="Sales Marketing Network">
                <span className="brand-mark" aria-hidden="true">
                  SM
                </span>
                <div className="brand-text">
                  <p className="brand-title">Sales Marketing Network</p>
                  <p className="brand-subtitle">Team-first revenue operations</p>
                </div>
              </div>

              <nav className="top-nav" aria-label="Primary navigation">
                <Link href="/">Dashboard</Link>
                <Link href="/">Pipeline</Link>
                <Link href="/">Team</Link>
                <Link href="/">Reports</Link>
              </nav>

              <div className="header-pill" aria-live="polite">
                <span className="status-dot" aria-hidden="true" />
                System Ready
              </div>
            </div>
          </header>

          <div className="container app-body">
            <aside className="sidebar" aria-label="Workspace sections">
              <p className="sidebar-title">Workspace</p>
              <ul className="sidebar-list">
                <li>Lead Database</li>
                <li>Deal Tracking</li>
                <li>Activity Feed</li>
                <li>Performance KPIs</li>
                <li>Export Center</li>
              </ul>
            </aside>

            <main id="main-content" className="main-content" role="main">
              {children}
            </main>
          </div>

          <footer className="app-footer" role="contentinfo">
            <div className="container footer-inner">
              <p>© {currentYear} Sales Marketing Network</p>
              <p>Built for high-velocity sales teams and measurable growth.</p>
            </div>
          </footer>
        </div>
      </body>
    </html>
  );
}

/*
  Global foundation for Sales Marketing Network
  - Design tokens
  - Accessibility primitives
  - Responsive app shell baseline
*/

:root {
  color-scheme: light;

  /* Typography */
  --font-sans-stack: var(--font-sans), Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto,
    Helvetica, Arial, sans-serif;
  --font-mono-stack: var(--font-mono), "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco,
    Consolas, "Liberation Mono", "Courier New", monospace;

  /* Core palette */
  --bg: #f7f9fc;
  --surface: #ffffff;
  --surface-muted: #f2f5fb;
  --border: #d9e1ef;
  --border-strong: #bcc9df;

  --text: #0f172a;
  --text-muted: #475569;
  --text-subtle: #64748b;

  --primary: #1d4ed8;
  --primary-strong: #1e40af;
  --primary-soft: #dbeafe;

  --success: #059669;
  --success-soft: #d1fae5;

  --danger: #dc2626;
  --warning: #d97706;

  /* Layout */
  --container-max: 1200px;
  --header-height: 76px;
  --footer-height: 64px;

  /* Spacing scale */
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-10: 2.5rem;

  /* Radius + shadow */
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;

  --shadow-sm: 0 1px 2px rgba(15, 23, 42, 0.08);
  --shadow-md: 0 10px 28px rgba(15, 23, 42, 0.08);

  /* Motion */
  --ease-standard: cubic-bezier(0.2, 0.8, 0.2, 1);
  --duration-fast: 160ms;
  --duration-normal: 260ms;
}

@media (prefers-color-scheme: dark) {
  :root {
    color-scheme: dark;

    --bg: #0b1020;
    --surface: #11182b;
    --surface-muted: #182035;
    --border: #2a3654;
    --border-strong: #3d4b6c;

    --text: #e2e8f0;
    --text-muted: #cbd5e1;
    --text-subtle: #94a3b8;

    --primary: #60a5fa;
    --primary-strong: #93c5fd;
    --primary-soft: rgba(96, 165, 250, 0.16);

    --success: #10b981;
    --success-soft: rgba(16, 185, 129, 0.16);

    --shadow-sm: 0 1px 2px rgba(2, 6, 23, 0.45);
    --shadow-md: 0 18px 40px rgba(2, 6, 23, 0.5);
  }
}

* {
  box-sizing: border-box;
}

*::before,
*::after {
  box-sizing: inherit;
}

html,
body {
  margin: 0;
  width: 100%;
  min-height: 100%;
}

body {
  font-family: var(--font-sans-stack);
  background: radial-gradient(1200px 600px at 100% -10%, var(--primary-soft), transparent 70%),
    var(--bg);
  color: var(--text);
  line-height: 1.5;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

img,
svg,
video,
canvas {
  display: block;
  max-width: 100%;
}

button,
input,
textarea,
select {
  font: inherit;
}

:focus-visible {
  outline: 3px solid var(--primary);
  outline-offset: 2px;
  border-radius: 6px;
}

::selection {
  background: var(--primary-soft);
  color: var(--text);
}

.skip-link {
  position: fixed;
  left: var(--space-4);
  top: -120px;
  z-index: 1000;
  background: var(--text);
  color: var(--surface);
  padding: var(--space-3) var(--space-4);
  border-radius: var(--radius-sm);
  transition: top var(--duration-fast) var(--ease-standard);
}

.skip-link:focus-visible {
  top: var(--space-4);
}

.container {
  width: min(var(--container-max), calc(100% - 2rem));
  margin-inline: auto;
}

.app-shell {
  min-height: 100dvh;
  display: grid;
  grid-template-rows: auto 1fr auto;
}

.app-header {
  position: sticky;
  top: 0;
  z-index: 30;
  backdrop-filter: saturate(150%) blur(12px);
  background: color-mix(in oklab, var(--surface) 90%, transparent);
  border-bottom: 1px solid var(--border);
}

.header-inner {
  min-height: var(--header-height);
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: var(--space-4);
  padding-block: var(--space-3);
}

.brand-block {
  display: inline-flex;
  align-items: center;
  gap: var(--space-3);
  min-width: 0;
}

.brand-mark {
  width: 2.25rem;
  height: 2.25rem;
  border-radius: 10px;
  display: inline-grid;
  place-items: center;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: #fff;
  background: linear-gradient(135deg, var(--primary), var(--primary-strong));
  box-shadow: var(--shadow-sm);
}

.brand-text {
  min-width: 0;
}

.brand-title {
  margin: 0;
  font-size: 0.98rem;
  font-weight: 700;
  line-height: 1.2;
  white-space: nowrap;
  text-overflow: ellipsis;
  overflow: hidden;
}

.brand-subtitle {
  margin: 0;
  color: var(--text-subtle);
  font-size: 0.8rem;
  line-height: 1.2;
}

.top-nav {
  display: inline-flex;
  justify-self: center;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-1);
  border: 1px solid var(--border);
  border-radius: 999px;
  background: var(--surface-muted);
}

.top-nav a {
  padding: 0.45rem 0.8rem;
  border-radius: 999px;
  font-size: 0.9rem;
  color: var(--text-muted);
  transition: background var(--duration-fast) var(--ease-standard),
    color var(--duration-fast) var(--ease-standard);
}

.top-nav a:hover {
  background: var(--primary-soft);
  color: var(--primary-strong);
}

.header-pill {
  justify-self: end;
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  border: 1px solid var(--border);
  background: var(--surface);
  padding: 0.45rem 0.75rem;
  border-radius: 999px;
  color: var(--text-muted);
  box-shadow: var(--shadow-sm);
  white-space: nowrap;
  font-size: 0.86rem;
}

.status-dot {
  width: 0.5rem;
  height: 0.5rem;
  border-radius: 999px;
  background: var(--success);
  box-shadow: 0 0 0 5px var(--success-soft);
}

.app-body {
  width: min(var(--container-max), calc(100% - 2rem));
  padding-block: var(--space-6);
  display: grid;
  grid-template-columns: 240px minmax(0, 1fr);
  gap: var(--space-6);
  align-items: start;
}

.sidebar {
  position: sticky;
  top: calc(var(--header-height) + 1rem);
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: var(--space-5);
  box-shadow: var(--shadow-sm);
}

.sidebar-title {
  margin: 0 0 var(--space-4);
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--text-subtle);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.sidebar-list {
  margin: 0;
  padding-left: 1rem;
  display: grid;
  gap: var(--space-2);
  color: var(--text-muted);
  font-size: 0.92rem;
}

.main-content {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: clamp(1rem, 1.2vw + 0.85rem, 1.5rem);
  min-height: 420px;
  box-shadow: var(--shadow-md);
}

.app-footer {
  border-top: 1px solid var(--border);
  background: var(--surface);
  min-height: var(--footer-height);
}

.footer-inner {
  min-height: var(--footer-height);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  color: var(--text-subtle);
  font-size: 0.86rem;
}

.footer-inner p {
  margin: 0;
}

@media (max-width: 960px) {
  .header-inner {
    grid-template-columns: 1fr auto;
    grid-template-areas:
      "brand status"
      "nav nav";
    row-gap: var(--space-3);
  }

  .brand-block {
    grid-area: brand;
  }

  .top-nav {
    grid-area: nav;
    justify-self: start;
    overflow-x: auto;
    max-width: 100%;
    scrollbar-width: thin;
  }

  .header-pill {
    grid-area: status;
  }

  .app-body {
    grid-template-columns: 1fr;
  }

  .sidebar {
    position: static;
    order: 2;
  }

  .main-content {
    order: 1;
  }

  .footer-inner {
    flex-direction: column;
    align-items: flex-start;
    justify-content: center;
    padding-block: var(--space-4);
  }
}

@media (max-width: 640px) {
  .container,
  .app-body {
    width: min(var(--container-max), calc(100% - 1rem));
  }

  .brand-subtitle {
    display: none;
  }

  .top-nav a {
    font-size: 0.84rem;
    padding: 0.4rem 0.7rem;
  }

  .header-pill {
    font-size: 0.8rem;
  }

  .main-content {
    border-radius: var(--radius-md);
    padding: var(--space-4);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.001ms !important;
    scroll-behavior: auto !important;
  }
}
